mapper.select:
SELECT h.id, h.user_id AS userId, h.attraction_content_id AS attractionContentId, h.visit_date AS date, h.description, h.created_at AS createdAt, h.updated_at AS updatedAt, u.email AS writerEmail, u.name AS writerName, a.title AS name, a.addr1 AS address, a.first_image1 AS imageUrl, a.first_image1 AS firstimage, COALESCE(ct.content_type_name, 'Hotplace') AS type, a.content_type_id AS contentTypeId, a.area_code AS areaCode, a.si_gun_gu_code AS siGunGuCode, a.latitude AS latitude, a.longitude AS longitude, a.latitude AS mapy, a.longitude AS mapx, popular.hotplaceCount FROM ( SELECT attraction_content_id, COUNT(*) AS hotplaceCount, MAX(id) AS latestHotplaceId FROM hotplaces GROUP BY attraction_content_id ) popular JOIN hotplaces h ON h.id = popular.latestHotplaceId JOIN users u ON u.id = h.user_id JOIN attractions a ON a.content_id = h.attraction_content_id LEFT JOIN contenttypes ct ON ct.content_type_id = a.content_type_id LEFT JOIN sidos s ON s.sido_code = a.area_code
a.area_code = #{areaCode}
s.sido_name LIKE CONCAT('%', #{region}, '%') OR a.addr1 LIKE CONCAT('%', #{region}, '%')
ORDER BY popular.hotplaceCount DESC, h.created_at DESC, h.id DESC LIMIT #{limit}

SELECT


WHERE h.user_id = #{userId}
ORDER BY h.created_at DESC, h.id DESC

SELECT EXISTS (
    SELECT 1
    FROM hotplaces
    WHERE user_id = #{userId}
      AND attraction_content_id = #{attractionContentId}
)

mapper.update:
UPDATE hotplaces
SET visit_date = #{date},
    description = #{description},
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND user_id = #{userId}

mapper.delete:
DELETE FROM hotplaces
WHERE id = #{id}
  AND user_id = #{userId}
